locs = list(Location.objects.order_by('id'))
for i, (name, desc, days) in enumerate(EVENTS):
    # Try manual mapping first, then fallback to round-robin
    target_loc_id = EVENT_LOC_MAP.get(name)
    if target_loc_id:
        try:
            loc = Location.objects.get(id=target_loc_id)
        except Location.DoesNotExist:
            loc = locs[i % len(locs)]
    else:
        loc = locs[i % len(locs)]
    
    # Simple mapping for event photos
    theme = "festival"
    n = name.lower()
    if "марафон" in n or "чемпионат" in n or "турнир" in n or "гонки" in n: theme = "marathon"
    elif "кинофестиваль" in n or "музыка" in n or "театр" in n or "балет" in n: theme = "concert"
    elif "биатлон" in n or "спорт" in n: theme = "sport"
    elif "форум" in n or "конференция" in n or "бизнес" in n: theme = "business"
    elif "выставка" in n or "ярмарка" in n: theme = "expo"
    elif "ночь" in n or "праздник" in n or "день" in n or "ёлка" in n: theme = "party"

    Event.objects.create(
        name=name, description=desc, location=loc,
        start_time=timezone.now() + datetime.timedelta(days=days),
        end_time=timezone.now() + datetime.timedelta(days=days, hours=6),
        photo_url=IMG.get(theme, IMG["festival"])
    )

print(f"Создано {Event.objects.count()} мероприятий!")

